import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as n,c as a,a as r}from"./chunks/runtime-core.esm-bundler.B-pbIWSu.js";const m=JSON.parse('{"title":"Navigating the New Money Laundering Directive 2082","description":"Understanding the new real estate transaction thresholds and compliance requirements.","frontmatter":{"title":"Navigating the New Money Laundering Directive 2082","description":"Understanding the new real estate transaction thresholds and compliance requirements.","date":"2024-05-20T00:00:00.000Z","author":"Artha Advisory Team","tags":["Compliance","Real Estate","AML"],"head":[["link",{"rel":"canonical","href":"https://arthaadvisory.com.np/resources/insights/money-laundering-directive-2082"}],["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/og_image_test.jpg"}],["meta",{"property":"og:title","content":"Navigating the New Money Laundering Directive 2082 | Artha Advisory"}],["meta",{"property":"og:description","content":"Understanding the new real estate transaction thresholds and compliance requirements."}],["meta",{"name":"description","content":"Understanding the new real estate transaction thresholds and compliance requirements."}]]},"headers":[],"relativePath":"resources/insights/money-laundering-directive-2082.md","filePath":"resources/insights/money-laundering-directive-2082.md"}'),o={name:"resources/insights/money-laundering-directive-2082.md"};function i(s,e,l,c,h,d){return n(),a("div",null,[...e[0]||(e[0]=[r('<p><strong>Is your real estate transaction compliant with the latest government directive?</strong></p><p>The Government of Nepal has recently issued the <strong>Money Laundering Prevention and Combating Terrorism Financing Directive, 2082</strong>, introducing stringent measures for high-value transactions, particularly in the real estate sector. This move aims to curb the flow of illicit funds and align Nepal with international Financial Action Task Force (FATF) standards.</p><h2 id="🚨-key-threshold-the-10-lakh-rule" tabindex="-1">🚨 Key Threshold: The 10 Lakh Rule <a class="header-anchor" href="#🚨-key-threshold-the-10-lakh-rule" aria-label="Permalink to &quot;🚨 Key Threshold: The 10 Lakh Rule&quot;">​</a></h2><p>The most significant change is the introduction of a lower threshold for mandatory &quot;Source of Funds&quot; declarations.</p><ul><li><strong>Old Rule:</strong> Scrutiny focused primarily on transactions above NPR 1 Crore.</li><li><strong>New Rule:</strong> Any land or property transaction exceeding <strong>NPR 10 Lakhs</strong> now requires the buyer to disclose the legitimate source of income.</li></ul><h2 id="📝-mandatory-banking-channels" tabindex="-1">📝 Mandatory Banking Channels <a class="header-anchor" href="#📝-mandatory-banking-channels" aria-label="Permalink to &quot;📝 Mandatory Banking Channels&quot;">​</a></h2><p>Cash is no longer king. The directive mandates that any payment for real estate exceeding the specified limit must be routed through banking channels.</p><ul><li><strong>Cheques / Drafts / RTGS:</strong> Must be used for the transaction value.</li><li><strong>Cash Payments:</strong> Strictly discouraged and may trigger a &quot;Suspicious Transaction Report&quot; (STR) by the Land Revenue Office (Malpot).</li></ul><h2 id="🏢-impact-on-real-estate-companies" tabindex="-1">🏢 Impact on Real Estate Companies <a class="header-anchor" href="#🏢-impact-on-real-estate-companies" aria-label="Permalink to &quot;🏢 Impact on Real Estate Companies&quot;">​</a></h2><p>If you are a developer or a housing company, your compliance burden has increased. You are now classified as a <strong>Reporting Entity</strong>. This means you must:</p><ol><li><strong>KYC:</strong> Maintain detailed Know Your Customer records for all buyers.</li><li><strong>Reporting:</strong> Automatically report transactions exceeding NPR 10 Lakhs to the Financial Information Unit (FIU) of Nepal Rastra Bank.</li><li><strong>Risk Assessment:</strong> Conduct an internal risk assessment of your clients.</li></ol><h2 id="⚠️-penalties-for-non-compliance" tabindex="-1">⚠️ Penalties for Non-Compliance <a class="header-anchor" href="#⚠️-penalties-for-non-compliance" aria-label="Permalink to &quot;⚠️ Penalties for Non-Compliance&quot;">​</a></h2><p>Failure to adhere to these new norms can result in:</p><ul><li>Freezing of the asset.</li><li>Fines up to <strong>500% of the transaction value</strong>.</li><li>Criminal prosecution for money laundering abetment.</li></ul><h2 id="✅-action-plan-for-buyers-sellers" tabindex="-1">✅ Action Plan for Buyers &amp; Sellers <a class="header-anchor" href="#✅-action-plan-for-buyers-sellers" aria-label="Permalink to &quot;✅ Action Plan for Buyers &amp; Sellers&quot;">​</a></h2><ol><li><strong>Document Everything:</strong> Keep tax clearance certificates and bank statements ready to prove your income source.</li><li><strong>Use Formal Channels:</strong> Avoid &quot;Undervaluation&quot; (Kaili Chodine) practices. The gap between the Government Valuation and Market Price is being closely monitored.</li><li><strong>Consult Experts:</strong> Before signing that deed, ensure your paper trail is clean.</li></ol><hr><p><em>Need help structuring your property deal legally? <a href="/contact">Contact Artha Advisory</a> for a consultation.</em></p>',18)])])}const p=t(o,[["render",i]]);export{m as __pageData,p as default};
